ValidationRule.errorConditionFormula:
AND(
    OR(
        ISPICKVAL(Onboarding_Stage__c , "Documents Pending"),
        AND(
            ISPICKVAL(PRIORVALUE(Onboarding_Stage__c ), "Documents Pending"),
            NOT(ISPICKVAL(Onboarding_Stage__c , "Documents Pending"))
        )
    ),
    ISBLANK(Pending_Documents__c )
)
